sql:
SELECT student_id, COUNT(document_id) AS total_documents
FROM student_documents
GROUP BY student_id;

SELECT student_id, note_text
FROM student_notes
WHERE note_date > '2023-04-20' AND note_text LIKE '%graduation%';

SELECT activity_name, completion_date
FROM career_development
ORDER BY completion_date DESC;

external_knowledge:
- 'Highly Active' students have more than 10 combined tasks, procedures, and reminders;
- 'Moderately Active' students have between 5 and 10 combined tasks, procedures, and reminders;
- 'Minimally Active' students have fewer than 5 combined tasks, procedures, and reminders.

- 'High-achieving students' refers to students with a GPA greater than 3.0;
- 'Completed tasks' refers to tasks with a status of 'completed';
- 'Details of their tasks' include the task names and the status of the tasks.

sql:
SELECT procedure_id, status
FROM student_procedures
WHERE status = 'Pending';

SELECT COUNT(student_id) 
FROM graduation_clearance 
WHERE status = 'Pending';

SELECT office_name, contact_email
FROM offices
WHERE office_id < 10;

SELECT COUNT(DISTINCT student_id) 
FROM student_documents 
WHERE document_name = 'Diploma' AND document_type = 'Diploma';

external_knowledge:
- 'Completed' status in tasks and procedures means all required actions are finished;
- 'Pending' status in graduation clearance indicates the process is not yet finalized;
- 'graduation application' notes are important for tracking student intentions and statuses.

sql:
SELECT COUNT(DISTINCT student_id) 
FROM exit_surveys 
WHERE survey_name = 'Graduate Exit Survey' AND completion_date IS NOT NULL;

external_knowledge:
- 'Upcoming survey' refers to a task that is a survey and has a deadline in the future;
- 'Transcript' is a type of document that students submit as part of their academic records;
- 'Procedure' refers to a specific administrative process that students need to complete, often with reminders set to ensure timely completion;
- 'Workshop' is a type of career development activity that students can participate in to enhance their skills.

- 'on the cusp of graduation' refers to students whose graduation clearance status is 'Pending';
- 'hurdles to clear' refers to pending tasks or requirements for graduation;
- 'crossed at least one milestone' refers to having completed at least one task.

sql:
SELECT task_id, status
FROM student_tasks
WHERE status = 'Completed';

SELECT COUNT(DISTINCT student_id) AS total_students
FROM student_tasks
WHERE task_id = 0 AND status = 'completed';

external_knowledge:
- "significant number of tasks" refers to more than 3 completed tasks;
- "significant number of procedures" refers to more than 2 completed procedures;
- "cleared for graduation" means the student has a clearance status of 'Cleared'.

sql:
SELECT COUNT(task_id) 
FROM student_tasks 
WHERE status = 'Pending';

SELECT COUNT(DISTINCT student_id) 
FROM student_notes 
WHERE note_text = 'Student submitted graduation application.';

external_knowledge:
- 'reached the peak of their academic journey' refers to students who have a graduation date;
- 'blossoming minds' refers to students;
- 'milestones' refer to completed tasks, completed procedures, and career development activities;
- 'officially bloom into graduates' refers to the clearance date in the graduation clearance process.
